INSERT INTO public.departments (id, name_en, name_hi, website) VALUES ('2c5ae0d5-a340-4379-bcf0-f008c2796f74', 'Rural Development Department, Government of Bihar', 'ग्रामीण विकास विभाग, बिहार सरकार', 'https://rdd.bihar.gov.in');
